file.content:
            break
        # Subtract the count that ARE divisible by p (and recursively handle rest)
        total -= _inclusion_exclusion(x // p, primes, i + 1)
    return total


@lru_cache(maxsize=None)
def _get_primes_up_to(n):
    """
    Return tuple of primes up to n, found recursively using legendre_pi.
    This is the bootstrapping mechanism.
    """
    if n < 2:
        return ()
    primes = []
    for candidate in range(2, n + 1):
        if _is_prime_by_known(candidate, primes):
            primes.append(candidate)
    return tuple(primes)


def _is_prime_by_known(x, known_primes):
    """Check if x is prime using only the known primes (trial division up to sqrt(x))."""
    if x < 2:
        return False
    sqrtx = int(math.isqrt(x))
    for p in known_primes:
        if p > sqrtx:
            break
        if x % p == 0:
            return False
    return True


def nth_prime_legendre(n):
    """Find nth prime using Legendre's pi(x) + binary search."""
    if n <= 0:
        raise ValueError("n must be >= 1")
    if n <= 6:
        return [2, 3, 5, 7, 11, 13][n - 1]

    # Bounds from prime number theorem
    ln_n = math.log(n)
    ln_ln_n = math.log(ln_n)
    lo = int(n * (ln_n + ln_ln_n - 1.5))
    hi = int(n * (ln_n + ln_ln_n + 1.0))

    while lo < hi:
        mid = (lo + hi) // 2
        if legendre_pi(mid) >= n:
            hi = mid
        else:
            lo = mid + 1
    return lo


# ============================================================
# APPROACH 2: Meissel's Formula for pi(x)
# ============================================================
# Meissel (1870) computed pi(x) using:
#   pi(x) = phi(x, a) + a - 1 - P2(x, a)
# where a = pi(x^{1/3}), and:
#   phi(x, a) = # integers in [1,x] not divisible by first a primes
#   P2(x, a)  = # integers in [1,x] with exactly 2 prime factors both > p_a
#
# phi(x,a) is computed recursively:
#   phi(x, 0) = x
#   phi(x, a) = phi(x, a-1) - phi(x/p_a, a-1)
#
# This is NOT a sieve. It's a pure recursive formula.

class MeisselPi:
    """Compute pi(x) using Meissel's formula with phi recursion."""

    def __init__(self):
        self._prime_cache = [2, 3, 5, 7, 11, 13]
        self._pi_cache = {}

    def _ensure_primes(self, limit):
        """Extend prime cache up to limit using constructive method."""
        if self._prime_cache and self._prime_cache[-1] >= limit:
            return
        start = self._prime_cache[-1] + 2 if self._prime_cache else 2
        for candidate in range(start, limit + 1):
            sqrtc = int(math.isqrt(candidate))
            is_p = True
            for p in self._prime_cache:
                if p > sqrtc:
                    break
                if candidate % p == 0:
                    is_p = False
                    break
            if is_p:
                self._prime_cache.append(candidate)

    def _prime(self, k):
        """Return the kth prime (1-indexed)."""
        while len(self._prime_cache) < k:
            self._ensure_primes(self._prime_cache[-1] + 100)
        return self._prime_cache[k - 1]

    def phi(self, x, a, memo=None):
        """
        phi(x, a) = # integers in [1,x] coprime to the first a primes.
        Recursive formula:
            phi(x, 0) = x
            phi(x, a) = phi(x, a-1) - phi(x/p_a, a-1)
        """
        if memo is None:
            memo = {}
        if a == 0:
            return int(x)
        if x <= 0:
            return 0
        key = (int(x), a)
        if key in memo:
            return memo[key]

        # Optimization: if p_a > x, all remaining primes are > x, so phi(x,a) = 1 if x >= 1
        pa = self._prime(a)
        if pa > x:
            result = max(1, int(x))  # 1 (just the number 1 itself) if x >= 1
            # Actually more precisely: count of integers in [1,x] coprime to first a primes
            # If smallest unused prime > x, then all integers 1..x coprime to smaller primes remain
            # This equals phi(x, a-1) since p_a > x means no multiples of p_a in [1,x]...
            # except p_a itself if p_a <= x. Since p_a > x, phi(x,a) = phi(x,a-1).
            result = self.phi(x, a - 1, memo)
            memo[key] = result
            return result

        result = self.phi(x, a - 1, memo) - self.phi(x // pa, a - 1, memo)
        memo[key] = result
        return result

    def pi(self, x):
        """
        Compute pi(x) using Meissel's formula:
          pi(x) = phi(x, a) + a - 1 - P2(x, a)
        where a = pi(x^{1/3}).
        """
        x = int(x)
        if x < 2:
            return 0
        if x < 3:
            return 1
        if x < 5:
            return 2
        if x < 7:
            return 3
        if x < 11:
            return 4
        if x < 13:
            return 5
        if x < 17:
            return 6

        if x in self._pi_cache:
            return self._pi_cache[x]

        # a = pi(x^{1/3})
        cbrt_x = int(x ** (1.0 / 3.0))
        # Correct floating point
        while (cbrt_x + 1) ** 3 <= x:
            cbrt_x += 1
        while cbrt_x ** 3 > x:
            cbrt_x -= 1

        a = self.pi(cbrt_x)

        sqrtx = int(math.isqrt(x))
        b = self.pi(sqrtx)

        # Ensure we have enough primes
        self._ensure_primes(sqrtx + 10)

        memo = {}
        phi_val = self.phi(x, a, memo)

        # P2(x, a) = sum over a < k <= b of pi(x / p_k) - (k - 1)
        # where b = pi(sqrt(x))
        p2 = 0
        for k in range(a + 1, b + 1):
            pk = self._prime(k)
            p2 += self.pi(x // pk) - (k - 1)

        result = phi_val + a - 1 - p2
        self._pi_cache[x] = result
        return result


_meissel = MeisselPi()


def nth_prime_meissel(n):
    """Find nth prime using Meissel's pi(x) + binary search."""
    if n <= 0:
        raise ValueError("n must be >= 1")
    if n <= 6:
        return [2, 3, 5, 7, 11, 13][n - 1]
